from qiskit.quantum_info import SparsePauliOp

# Map the 2-qubit observable ZZ onto physical qubits [2, 0] of a 4-qubit register.
result = SparsePauliOp("ZZ").apply_layout([2, 0], num_qubits=4)
observed = str(result.paulis[0])

candidates = {"A": "IZIZ", "B": "ZIZI", "C": "ZZII", "D": "IIZZ"}
evidence = {}
proven = []
for k, val in candidates.items():
    m = (observed == val)
    evidence[k] = f"SparsePauliOp('ZZ').apply_layout([2,0], num_qubits=4) -> '{observed}'; option claims '{val}' -> match={m}"
    if m:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"label": observed}})
